21	- (void)configBleConnectStateObservation {
22	    if ([CTMediator hasBleAbility] && [XPBLEKeyManager.instance isSafeKeyOrCertKeyExisted]) {
23	        DLogTagInfo(kCarSettingTag, @"订阅蓝牙连接状态");
24	        if(self.bleConnectStateDisposable) {
25	            [self.rac_deallocDisposable removeDisposable:self.bleConnectStateDisposable];
26	            [self.bleConnectStateDisposable dispose];
27	        }
28	        @weakify(self);
29	        self.bleConnectStateDisposable = [XPBLEHandlerManager.manager.sendBleConnectStateSingal.deliverOnMainThread subscribeNext:^(id  _Nullable x) {
30	            @strongify(self);
31	            if ([x isKindOfClass:NSDictionary.class]) {
32	                NSDictionary *stateDict = (NSDictionary *)x;
33	                BOOL isCommunicate = [stateDict[XP_BLEKEY_IS_COMMUNICATE_KEY] boolValue];
34	                if (!isCommunicate) {
35	                    return;
36	                }
37	                XPBLEHanderConnectState connectState = (XPBLEHanderConnectState)[stateDict[XP_BLEKEY_CONNECT_STATE_KEY] intValue];
38	                NSArray *connectStatesDebug = @[@"XPBLEHanderConnectStateDisconnect",
39	                                                @"XPBLEHanderConnectStateConnecting",
40	                                                @"XPBLEHanderConnectStateConnected",
41	                                                @"XPBLEHanderConnectStateAuthorized",
42	                                                @"XPBLEHanderConnectStateDisconnecting"];
43	                PHSettingBleItem *bleItem = (PHSettingBleItem *)[self findItemWithIndex:PHSettingIndexKeyCheck];
44	                if(connectState == XPBLEHanderConnectStateAuthorized) {
45	                    bleItem.bleLogoImageName = @"coh_ic_ble_active";
46	                    bleItem.subtitle = CTMediator.isE28? kBleCheckDescWhenConnectedForE28:kBleCheckDescWhenConnectedForNewCar;
47	                    DLogTagInfo(kCarSettingTag, @"蓝牙已连接，可启动车辆，蓝牙连接状态:%@", connectStatesDebug[connectState]);
48	                } else {
49	                    bleItem.bleLogoImageName = @"coh_ic_ble_inactive";
50	                    bleItem.subtitle = kBleCheckDescWhenDisconnected;
51	                    DLogTagInfo(kCarSettingTag, @"未连接，无法启动车辆:%@", connectStatesDebug[connectState]);
52	                }
53	                [self.tableView reloadData];
54	            } else {
55	                DLogTagInfo(kCarSettingTag, @"connectStateNumber为空，获取不到蓝牙连接状态");
56	            }
57	        }];
58	        [self.rac_deallocDisposable addDisposable:self.bleConnectStateDisposable];
59	    } else {
60	        if(self.bleConnectStateDisposable) {
61	            DLogTagInfo(kCarSettingTag, @"取消订阅蓝牙连接状态");
62	            [self.rac_deallocDisposable removeDisposable:self.bleConnectStateDisposable];
63	            [self.bleConnectStateDisposable dispose];
64	        } else {
65	            DLogTagInfo(kCarSettingTag, @"self.bleConnectStateDisposable为空，do nothing");
66	        }
67	    }
68	}
