70	- (void)configBleConnectStateObservationSDK2nd:(XPVehicleData *)data {
71	    if(data.function.BLE_KEY && [self isExistValidBleKey]) {
72	        DLogTagInfo(kCarSettingTag, @"订阅蓝牙连接状态 Sdk 2nd");
73	        if(self.bleConnectStateDisposable) {
74	            [self.rac_deallocDisposable removeDisposable:self.bleConnectStateDisposable];
75	            [self.bleConnectStateDisposable dispose];
76	        }
77	        @weakify(self);
78	        self.bleConnectStateDisposable = [[[[NSNotificationCenter defaultCenter] rac_addObserverForName:XPVehicleNotification.BLEConnectStateChanged object:nil] deliverOnMainThread] subscribeNext:^(NSNotification * _Nullable x) {
79	            @strongify(self)
80	            XPBLEConnectionNotiObject *object = x.userInfo[@"state"];
81	            if (![object isKindOfClass:[XPBLEConnectionNotiObject class]]) {
82	                return;
83	            }
84	            XPBLEConnectionState state = object.connectState;
85	            PHSettingBleItem *bleItem = (PHSettingBleItem *)[self findItemWithIndex:PHSettingIndexKeyCheck];
86	            if (bleItem == nil) {
87	                return;
88	            }
89	            if (state == XPBLEConnectionStateAvailable) {
90	                bleItem.bleLogoImageName = @"coh_ic_ble_active";
91	                bleItem.subtitle = CTMediator.isE28? kBleCheckDescWhenConnectedForE28:kBleCheckDescWhenConnectedForNewCar;
92	                DLogTagInfo(kCarSettingTag, @"蓝牙已连接，可启动车辆，蓝牙连接状态: XPBLEConnectionStateAvailable");
93	            } else {
94	                bleItem.bleLogoImageName = @"coh_ic_ble_inactive";
95	                bleItem.subtitle = kBleCheckDescWhenDisconnected;
96	                DLogTagInfo(kCarSettingTag, @"未连接，无法启动车辆 state:%ld", state);
97	            }
98	            [self.tableView reloadData];
99	        }];
100	        [self.rac_deallocDisposable addDisposable:self.bleConnectStateDisposable];
101	    } else {
102	        if(self.bleConnectStateDisposable) {
103	            DLogTagInfo(kCarSettingTag, @"取消订阅蓝牙连接状态 Sdk 2nd");
104	            [self.rac_deallocDisposable removeDisposable:self.bleConnectStateDisposable];
105	            [self.bleConnectStateDisposable dispose];
106	        } else {
107	            DLogTagInfo(kCarSettingTag, @"self.bleConnectStateDisposable为空，do nothing");
108	        }
109	    }
110	}
