266	            DLogTagInfo(kFileTransferUrgentTag, @"已连接到服务端共享的热点！");
267	            if (!self.isConnectedToAp) {
268	                DLogTagInfo(kFileTransferUrgentTag, @"步骤三：已连接想要的wifi");
269	                self.isConnectedToAp = YES; //设置连接ap状态
270	                
271	                //之前未连接到热点，则初始化所有状态
272	                if (!self.hasSetUDP) {
273	                    [self backFromSetting];
274	                }
275	                //[self initWhileConnectToAp];
276	            }
277	        } else {
278	            //wifi下，但非服务器共享热点的网段，则需要主动断开连接
279	            DLogTagInfo(kFileTransferUrgentTag, @"wifi下，但非服务器共享热点的网段，则需要主动断开连接");
