312	//处理数据
313	- (NSString *)segmentation:(XPTBoxMessage*)tboxMessage headerType:(XPBLEKeyMessageType)headerType {
314	    
315	    NSMutableString *strSend = [NSMutableString new];
316	    
317	    NSMutableData* data = [NSMutableData dataWithData:serializationXPTBoxMessage(tboxMessage)];
318	    const NSRange range = NSMakeRange(0, kPieceSize);
319	    NSMutableArray* array = [NSMutableArray arrayWithCapacity:ceil(data.length/kPieceSize)];
320	    while (0!=data.length) {
321	        if (data.length>kPieceSize) {
322	            [array addObject: [data subdataWithRange:range]];
323	            [data replaceBytesInRange:range withBytes:NULL length:0];
324	        } else {
325	            [array addObject:[NSData dataWithData:data]];
326	            break;
327	        }
328	    }
329	    
330	    for (NSInteger index = 0; index<array.count; ++index) {
331	        NSData* data = [array objectAtIndex:index];
332	        XPBLEKeyMessage* msg = createXPBLEKeyDataMessage(array.count,index+1,data.length, XPBLEKeyMessageTypeData);
333	        XPBLEKeyMessageSetPayload(msg, (void*)(data.bytes), data.length);
334	        
335	        for (int index = 0; index<msg->dataLength; ++index) {
336	            [strSend appendFormat:@"%02X",msg->dataPayload[index]];
337	        }
338	
339	        releaseXPBLEKeyMessage(msg);
340	    }
341	    DLogTagInfo(kBLEKeyTag, @"发送消息给车机蓝牙 msg = %@",strSend);
342	    return [NSString stringWithString:strSend];;
343	}
