432	- (void)sendUdpResponseMessage:(BOOL)isAccept
433	{
434	    //isAccept = YES;
435	    //构造响应消息
436	    XPFileTransferMessage *udpMsg = [self genUdpMessageModel];
437	    udpMsg.action = isAccept ? XPFileTransferMessageActionClientToServerAccept : XPFileTransferMessageActionClientToServerReject;
438	    
439	    if (!isAccept) {
440	        //拒绝接收文件
441	        //只需要发送一次响应消息
442	        DLogTagInfo(kFileTransferUrgentTag, @"拒绝接收文件");
443	        [self sendUdpMessage:[udpMsg jsonString] withTag:udpMsg.action];
444	    } else {
445	        //准备接收文件
446	        dispatch_async(dispatch_get_global_queue(0, 0), ^{
447	            //每隔2秒，发送一次接收文件的响应消息
448	            NSUInteger udpMsgCount = 1;
449	            //接收进程未结束的情况下，如果发送握手消息后，服务端未返回响应消息，则每隔2秒发送一次握手消息
450	            while (!self.isUdpHandshakeFinished) {
451	                DLogTagInfo(kFileTransferUrgentTag, @"准备接收文件，发送次数->%@", @(udpMsgCount));
452	                [self sendUdpMessage:[udpMsg jsonString] withTag:udpMsg.action];
453	                if (udpMsgCount>200) {
454	                    self.isUdpHandshakeFinished = YES;
455	                }
456	                udpMsgCount++;
457	                //休眠2秒
458	                sleep(2);
459	            }
460	        });
461	        
462	    }
463	}
