467	- (void)sendUdpMessage:(NSString *)msg withTag:(NSInteger)tag
468	{
469	    NSString *serverIp = self.serverIp;
470	    if (serverIp == nil || ![serverIp containsString:HOST_PREFIX]) {
471	        //serverIp不正确
472	        //发送广播消息
473	        serverIp = SERVER_IP_BROADCAST;
474	    }
475	    
476	    //防止服务端的端口被占用，从AP_UDP_ACCEPT_PORT开始递减，需要尝试三次
477	    for (int i = 0; i < PORT_RETRY_TIME; i++) {
478	        DLogTagInfo(kFileTransferUrgentTag, @"客户端发送udp响应信息: server ip->%@ port->%@, msg->%@", serverIp, @(AP_UDP_ACCEPT_PORT-i), msg);
479	        if (!self.udpSocket) {
480	            return;
481	        }
482	        NSData *data = [msg dataUsingEncoding:NSUTF8StringEncoding];
483	        [self.udpSocket sendData:data toHost:serverIp port:AP_UDP_ACCEPT_PORT-i withTimeout:-1 tag:tag];
484	    }
485	}
