- (NSString *)segmentation:(XPTBoxMessage*)tboxMessage headerType:(XPBLEKeyMessageType)headerType {

    NSMutableString *strSend = [NSMutableString new];

    NSMutableData* data = [NSMutableData dataWithData:serializationXPTBoxMessage(tboxMessage)];
    const NSRange range = NSMakeRange(0, kPieceSize);
    NSMutableArray* array = [NSMutableArray arrayWithCapacity:ceil(data.length/kPieceSize)];
    while (0!=data.length) {
        if (data.length>kPieceSize) {
            [array addObject: [data subdataWithRange:range]];
            [data replaceBytesInRange:range withBytes:NULL length:0];
        } else {
            [array addObject:[NSData dataWithData:data]];
            break;
        }
    }

    for (NSInteger index = 0; index<array.count; ++index) {
        NSData* data = [array objectAtIndex:index];
        XPBLEKeyMessage* msg = createXPBLEKeyDataMessage(array.count,index+1,data.length, XPBLEKeyMessageTypeData);
        XPBLEKeyMessageSetPayload(msg, (void*)(data.bytes), data.length);

        for (int index = 0; index<msg->dataLength; ++index) {
            [strSend appendFormat:@"%02X",msg->dataPayload[index]];
        }

        releaseXPBLEKeyMessage(msg);
    }
    DLogTagInfo(kBLEKeyTag, @"发送消息给车机蓝牙 msg = %@",strSend);
    return [NSString stringWithString:strSend];;
}

