}

- (void)dealWithIffaMsg:(NSString *)ifaaMsg cmd:(XPTBoxCommand )cmd{
    NSString *iffaStr = ifaaMsg;
    NSMutableData* mData = [[NSMutableData alloc] initWithBase64EncodedString:iffaStr options:NSDataBase64DecodingIgnoreUnknownCharacters];
    [mData appendBytes:&cmd length:sizeof(cmd)];

    XPTBoxMessage* tboxMessage = createXPTBoxMessage(mData.length);
    XPTBoxMessageSetPayLoad(tboxMessage, mData,0);
    NSString *sendStr = [self segmentation:tboxMessage headerType:XPBLEKeyMessageTypeData];
    releaseXPTBoxMessage(tboxMessage);
    [self dealWithSendStr:sendStr];
}

