- (void)sendSafeKeyCommand:(XPTBoxCommand )cmd{
    NSString* cardNo = XPBLEKeyManager.instance.defaultCard.cardNo;
    if (cardNo.length == 0) {
        [XPToast showMessage:@"卡号为空"];
    }
    [[[XPBLEKeyManager.instance.getTokenCommand execute:cardNo].deliverOnMainThread takeUntil:self.rac_willDeallocSignal] subscribeError:^(NSError * _Nullable error) {
        [XPToast showMessage:@"获取token失败"];

    }completed:^{
        [[[XPBLEKeyManager.instance.verifyCommand execute:nil] takeUntil:self.rac_willDeallocSignal].deliverOnMainThread subscribeNext:^(NSString*  _Nullable ifaaMsg) {
            //获取到报文了
            DLogTagInfo(kBLEKeyTag, @"报文是%@",ifaaMsg);
            //这里发送报文
            [self dealWithIffaMsg:ifaaMsg cmd:cmd];
        }];
    }];
}

