- (void)configBleConnectStateObservation {
    if ([CTMediator hasBleAbility] && [XPBLEKeyManager.instance isSafeKeyOrCertKeyExisted]) {
        DLogTagInfo(kCarSettingTag, @"订阅蓝牙连接状态");
        if(self.bleConnectStateDisposable) {
            [self.rac_deallocDisposable removeDisposable:self.bleConnectStateDisposable];
            [self.bleConnectStateDisposable dispose];
        }
        @weakify(self);
        self.bleConnectStateDisposable = [XPBLEHandlerManager.manager.sendBleConnectStateSingal.deliverOnMainThread subscribeNext:^(id  _Nullable x) {
            @strongify(self);
            if ([x isKindOfClass:NSDictionary.class]) {
                NSDictionary *stateDict = (NSDictionary *)x;
                BOOL isCommunicate = [stateDict[XP_BLEKEY_IS_COMMUNICATE_KEY] boolValue];
                if (!isCommunicate) {
                    return;
                }
                XPBLEHanderConnectState connectState = (XPBLEHanderConnectState)[stateDict[XP_BLEKEY_CONNECT_STATE_KEY] intValue];
                NSArray *connectStatesDebug = @[@"XPBLEHanderConnectStateDisconnect",
                                                @"XPBLEHanderConnectStateConnecting",
                                                @"XPBLEHanderConnectStateConnected",
                                                @"XPBLEHanderConnectStateAuthorized",
                                                @"XPBLEHanderConnectStateDisconnecting"];
                PHSettingBleItem *bleItem = (PHSettingBleItem *)[self findItemWithIndex:PHSettingIndexKeyCheck];
                if(connectState == XPBLEHanderConnectStateAuthorized) {
                    bleItem.bleLogoImageName = @"coh_ic_ble_active";
                    bleItem.subtitle = CTMediator.isE28? kBleCheckDescWhenConnectedForE28:kBleCheckDescWhenConnectedForNewCar;
                    DLogTagInfo(kCarSettingTag, @"蓝牙已连接，可启动车辆，蓝牙连接状态:%@", connectStatesDebug[connectState]);
                } else {
                    bleItem.bleLogoImageName = @"coh_ic_ble_inactive";
                    bleItem.subtitle = kBleCheckDescWhenDisconnected;
                    DLogTagInfo(kCarSettingTag, @"未连接，无法启动车辆:%@", connectStatesDebug[connectState]);
                }
                [self.tableView reloadData];
            } else {
                DLogTagInfo(kCarSettingTag, @"connectStateNumber为空，获取不到蓝牙连接状态");
            }
        }];
        [self.rac_deallocDisposable addDisposable:self.bleConnectStateDisposable];
    } else {
        if(self.bleConnectStateDisposable) {
            DLogTagInfo(kCarSettingTag, @"取消订阅蓝牙连接状态");
            [self.rac_deallocDisposable removeDisposable:self.bleConnectStateDisposable];
            [self.bleConnectStateDisposable dispose];
        } else {
            DLogTagInfo(kCarSettingTag, @"self.bleConnectStateDisposable为空，do nothing");
        }
    }
}

